import{_ as a,o as e,c as s,a2 as n}from"./chunks/framework.D6tuaLBS.js";const m=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"hermes_agent_docs/guide/getting-started.md","filePath":"hermes_agent_docs/guide/getting-started.md"}'),d={name:"hermes_agent_docs/guide/getting-started.md"};function r(l,t,p,o,i,c){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><blockquote><p>Hermes Agent 开源源码学习指南</p></blockquote><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>Hermes Agent 是 Nous Research 开源的通用 AI Agent 平台，用 Python 实现。核心差异化在于：多平台网关（15+ 平台）、技能生态（50+ 技能目录）、RL 训练支持（轨迹保存/压缩 + Atropos 集成）。</p><h2 id="项目统计" tabindex="-1">项目统计 <a class="header-anchor" href="#项目统计" aria-label="Permalink to &quot;项目统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>语言</td><td>Python</td></tr><tr><td>技能目录</td><td>50+</td></tr><tr><td>支持平台</td><td>15+（CLI、Telegram、Discord、WhatsApp、Slack、Signal、Email、SMS、Matrix、DingTalk、Feishu、WeCom 等）</td></tr><tr><td>工具数量</td><td>30+（分布在 10+ toolset 中）</td></tr><tr><td>许可证</td><td>Apache-2.0</td></tr></tbody></table><h2 id="架构总览" tabindex="-1">架构总览 <a class="header-anchor" href="#架构总览" aria-label="Permalink to &quot;架构总览&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hermes-agent（仓库根目录）</span></span>
<span class="line"><span>├── run_agent.py              ← AIAgent 主循环（CLI / 网关入口）</span></span>
<span class="line"><span>├── environments/</span></span>
<span class="line"><span>│   └── agent_loop.py         ← HermesAgentLoop（RL 训练用轻量循环）</span></span>
<span class="line"><span>├── gateway/                  ← 多平台网关</span></span>
<span class="line"><span>│   ├── platforms/            ← 各平台适配器</span></span>
<span class="line"><span>│   ├── session.py            ← 会话管理</span></span>
<span class="line"><span>│   ├── delivery.py           ← 消息投递路由</span></span>
<span class="line"><span>│   ├── hooks.py              ← Hook 注册表</span></span>
<span class="line"><span>│   └── stream_consumer.py    ← 流式消费</span></span>
<span class="line"><span>├── agent/                    ← Agent 内部模块</span></span>
<span class="line"><span>│   ├── context_compressor.py ← 上下文压缩器</span></span>
<span class="line"><span>│   ├── memory_manager.py     ← 记忆管理器</span></span>
<span class="line"><span>│   ├── prompt_builder.py     ← 系统提示词组装</span></span>
<span class="line"><span>│   ├── smart_model_routing.py← 智能模型路由</span></span>
<span class="line"><span>│   ├── prompt_caching.py     ← Anthropic 提示缓存</span></span>
<span class="line"><span>│   └── trajectory.py         ← 轨迹保存</span></span>
<span class="line"><span>├── tools/                    ← 工具实现（自注册模式）</span></span>
<span class="line"><span>│   ├── registry.py           ← ToolRegistry 单例</span></span>
<span class="line"><span>│   ├── terminal_tool.py      ← 终端工具</span></span>
<span class="line"><span>│   ├── file_tools.py         ← 文件工具</span></span>
<span class="line"><span>│   ├── browser_tool.py       ← 浏览器工具</span></span>
<span class="line"><span>│   ├── delegate_tool.py      ← 子 Agent 委托</span></span>
<span class="line"><span>│   └── ...</span></span>
<span class="line"><span>├── skills/                   ← 50+ 技能目录</span></span>
<span class="line"><span>├── toolsets.py               ← Toolset 定义与解析</span></span>
<span class="line"><span>├── model_tools.py            ← 工具发现与分发</span></span>
<span class="line"><span>├── trajectory_compressor.py  ← 轨迹压缩器（RL 后处理）</span></span>
<span class="line"><span>└── hermes_cli/               ← CLI 界面</span></span>
<span class="line"><span>    ├── cli.py                ← curses UI</span></span>
<span class="line"><span>    └── providers.py          ← Provider 解析</span></span></code></pre></div><h2 id="与-claude-code-codex-vercel-ai-sdk-的关键差异" tabindex="-1">与 Claude Code / Codex / Vercel AI SDK 的关键差异 <a class="header-anchor" href="#与-claude-code-codex-vercel-ai-sdk-的关键差异" aria-label="Permalink to &quot;与 Claude Code / Codex / Vercel AI SDK 的关键差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Hermes Agent</th><th>Claude Code</th><th>Codex CLI</th><th>Vercel AI SDK</th></tr></thead><tbody><tr><td>语言</td><td>Python</td><td>TypeScript (Bun)</td><td>Rust + TS</td><td>TypeScript</td></tr><tr><td>Agent Loop</td><td>双循环（AIAgent + HermesAgentLoop）</td><td>while(true) ReAct</td><td>事件驱动</td><td>streamText 循环</td></tr><tr><td>平台</td><td>15+ 平台网关</td><td>CLI only</td><td>CLI only</td><td>框架集成</td></tr><tr><td>技能系统</td><td>50+ SKILL.md 目录</td><td>—</td><td>—</td><td>—</td></tr><tr><td>RL 训练</td><td>轨迹保存 + Atropos</td><td>—</td><td>—</td><td>—</td></tr><tr><td>上下文压缩</td><td>50% 阈值 + 结构化摘要</td><td>92% 阈值 + 五层防爆</td><td>自动压缩 + 截断</td><td>maxSteps 控制</td></tr><tr><td>记忆</td><td>MemoryManager + Provider 插件</td><td>CLAUDE.md + Auto Memory</td><td>AGENTS.md + 配置</td><td>无内置</td></tr><tr><td>工具并行</td><td>读写分离 + 路径重叠检测</td><td>读写分区批次</td><td>串行</td><td>并行 tool calls</td></tr><tr><td>模型路由</td><td>关键词启发式（cheap/strong）</td><td>单模型</td><td>单模型</td><td>多 Provider</td></tr><tr><td>沙箱</td><td>Docker/Modal/Daytona 后端</td><td>OS 级 Seatbelt/Bubblewrap</td><td>OS 级 Landlock/Seatbelt</td><td>无</td></tr></tbody></table><h2 id="核心术语速查" tabindex="-1">核心术语速查 <a class="header-anchor" href="#核心术语速查" aria-label="Permalink to &quot;核心术语速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td>AIAgent</td><td><code>run_agent.py</code> 中的全功能 Agent 类，用于 CLI 和网关</td></tr><tr><td>HermesAgentLoop</td><td><code>environments/agent_loop.py</code> 中的轻量循环，用于 RL 训练</td></tr><tr><td>ToolRegistry</td><td>工具注册表单例，所有工具通过自注册模式加入</td></tr><tr><td>MemoryManager</td><td>记忆管理器，编排内置 + 最多 1 个外部 Provider</td></tr><tr><td>ContextCompressor</td><td>上下文压缩器，50% 阈值触发结构化 LLM 摘要</td></tr><tr><td>Gateway</td><td>多平台网关，统一消息路由和会话管理</td></tr><tr><td>Skills</td><td>SKILL.md 格式的技能文档，50+ 目录，条件激活</td></tr><tr><td>Toolsets</td><td>工具集合定义，支持组合和循环检测</td></tr><tr><td>IterationBudget</td><td>线程安全的迭代计数器，父 90 / 子 50</td></tr><tr><td>TrajectoryCompressor</td><td>RL 训练后处理，压缩轨迹到目标 token 预算</td></tr></tbody></table><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><ol><li><a href="/ai_harness/hermes_agent_docs/agent/dual-loop.html">双 Agent 循环</a> — 理解核心 Agent Loop 双轨设计</li><li><a href="/ai_harness/hermes_agent_docs/agent/parallel-tools.html">并行工具执行</a> — 理解读写分离的并行策略</li><li><a href="/ai_harness/hermes_agent_docs/context/compressor.html">上下文压缩器</a> — 理解 50% 阈值 + 结构化摘要</li><li><a href="/ai_harness/hermes_agent_docs/skills/skill-system.html">技能系统</a> — 理解 SKILL.md 生态</li><li><a href="/ai_harness/hermes_agent_docs/gateway/architecture.html">网关架构</a> — 理解多平台统一接入</li><li><a href="/ai_harness/hermes_agent_docs/tools/registry.html">工具注册表</a> — 理解自注册模式</li><li><a href="/ai_harness/hermes_agent_docs/memory/manager.html">记忆管理器</a> — 理解 Provider 插件架构</li><li><a href="/ai_harness/hermes_agent_docs/rl/agent-loop.html">RL Agent 循环</a> — 理解训练环境集成</li></ol>`,14)])])}const g=a(d,[["render",r]]);export{m as __pageData,g as default};
